import base64
import requests
import xml.etree.ElementTree as ET
from urllib.parse import quote

class SAMLServiceProvider:
    def __init__(self, destination_url, user_info):
        self.destination_url = destination_url
        self.user_info = user_info

    def create_authn_request(self):
        saml_request_template = """<?xml version="1.0" encoding="UTF-8"?>
        <s:Envelope xmlns:s="http://www.w3.org/2003/05/soap-envelope">
            <s:Header/>
            <s:Body>
                <AuthnRequest xmlns="urn:oasis:names:tc:SAML:2.0:protocol"
                    ID="{request_id}"
                    Version="2.0"
                    IssueInstant="{issue_instant}"
                    Destination="{destination_url}"
                    AssertionConsumerServiceURL="{acs_url}"
                    ProtocolBinding="urn:oasis:names:tc:SAML:2.0:bindings:HTTP-POST">
                    <Issuer>{issuer}</Issuer>
                    <NameIDPolicy AllowCreate="true"/>
                    <RequestedAuthnContext>
                        <AuthnContextClassRef>urn:oasis:names:tc:SAML:2.0:ac:classes:PasswordProtectedTransport</AuthnContextClassRef>
                    </RequestedAuthnContext>
                </AuthnRequest>
            </s:Body>
        </s:Envelope>"""

        request_id = self.generate_request_id()
        issue_instant = self.get_issue_instant()
        acs_url = self.user_info.get('acs_url', '')  # Assertion Consumer Service URL
        issuer = self.user_info.get('issuer', '')  # Entity ID of the Service Provider

        saml_request = saml_request_template.format(
            request_id=request_id,
            issue_instant=issue_instant,
            destination_url=self.destination_url,
            acs_url=acs_url,
            issuer=issuer
        )

        return base64.b64encode(saml_request.encode('utf-8')).decode('utf-8')

    def generate_request_id(self):
        import uuid
        return f"_{uuid.uuid4()}"

    def get_issue_instant(self):
        from datetime import datetime
        return datetime.utcnow().isoformat() + "Z"

    def send_authn_request(self):
        saml_request = self.create_authn_request()
        params = {'SAMLRequest': saml_request}
        response = requests.post(self.destination_url, data=params)
        return response


